import os
import re

tests_dir = "/home/barista/agentic_barista/runs/synthesize/serversocket/run_4/serversocket/tests"

# Replacement map: [type name] -> value
replacements = {
    "[SocketImpl impl]": "null",
    "[SocketAddress endpoint]": "null",
    "[int backlog]": "50",
    "[int port]": "0",
    "[InetAddress bindAddr]": "null",
    "[int timeout]": "1000",
    "[boolean on]": "true",
    "[int size]": "1024",
    "[int connectionTime]": "0",
    "[int latency]": "0",
    "[int bandwidth]": "0",
    "[SocketOption T]": "null",
    "[Socket s]": "null",
    "[SocketImplFactory fac]": "null",
}

# Imports to add
IMPORTS = """import java.net.ServerSocket;
import java.net.Socket;
import java.net.SocketAddress;
import java.net.InetAddress;
import java.net.SocketImpl;
import java.net.SocketImplFactory;
import java.net.ServerSocketChannel;
import java.net.SocketOption;
import java.io.IOException;
"""

def process_file(filepath):
    with open(filepath, 'r') as f:
        content = f.read()

    original = content

    # Apply all replacements
    for placeholder, value in replacements.items():
        content = content.replace(placeholder, value)

    # Add imports after the package declaration
    if "import java.net.ServerSocket;" not in content:
        # Find package line
        pkg_match = re.search(r'^(package [^;]+;)\s*\n', content, re.MULTILINE)
        if pkg_match:
            insert_pos = pkg_match.end()
            content = content[:insert_pos] + "\n" + IMPORTS + "\n" + content[insert_pos:]
        else:
            content = IMPORTS + "\n" + content

    if content != original:
        with open(filepath, 'w') as f:
            f.write(content)
        return True
    return False

count = 0
for root, dirs, files in os.walk(tests_dir):
    for fname in files:
        if fname.endswith(".java"):
            fpath = os.path.join(root, fname)
            if process_file(fpath):
                count += 1
                print(f"Updated: {fpath}")

print(f"\nTotal files updated: {count}")
EOF
